import unittestfrom htmlnode import HTMLNode,LeafNode, ParentNode, text_node_to_html_nodefrom textnode import TextNode, TextTypeclass TestHTMLNode(unittest.TestCase):    def test_eq(self):        node = HTMLNode(tag="foo", value="31", children="adsd", props={"a":2})        self.assertEqual(node.tag, "foo")    def text_repr(self):        node = HTMLNode(tag="foo", value="31", children="adsd", props={"a":2})        self.assertEqual(str(node), """HTMLNode(            tag=foo,             value=31,             children=adsd,            props={'a': 2})""")    def text_props_to_html(self):        node = HTMLNode(tag="foo", value="31", children="adsd", props={"a":2})        self.assertEqual(node.props_to_html(), 'a="2"')class TestLeafNode(unittest.TestCase):    def test_leaf_to_html_p(self):        node = LeafNode("p", "Hello, world!")        self.assertEqual(node.to_html(), "<p>Hello, world!</p>")class TestParentNode(unittest.TestCase):       def test_to_html_with_children(self):        child_node = LeafNode("span", "child")        parent_node = ParentNode("div", [child_node])        self.assertEqual(parent_node.to_html(), "<div><span>child</span></div>")        def test_to_html_with_grandchildren(self):        grandchild_node = LeafNode("b", "grandchild")        child_node = ParentNode("span", [grandchild_node])        parent_node = ParentNode("div", [child_node])        self.assertEqual(            parent_node.to_html(),            "<div><span><b>grandchild</b></span></div>",        )                class TestTextNodetoHTMLNode(unittest.TestCase):            def test_text(self):        node = TextNode("This is a text node", TextType.TEXT)        html_node = text_node_to_html_node(node)        self.assertEqual(html_node.tag, None)        self.assertEqual(html_node.value, "This is a text node")if __name__ == "__main__":    unittest.main()